export const DUMMY_VENDOR_GST_LOOKUP = DUMMY_VENDOR_LIST.reduce((lookup, vendor) => {
  const registrations = Array.isArray(vendor.gstRegistrations) ? vendor.gstRegistrations : [];
  registrations.forEach((registration) => {
    lookup.byGstin[registration.gstin] = {
      ...registration,
      legalName: vendor.name,
      pan: vendor.pan,
      vendorType: vendor.vendor_type,
      email: vendor.email,
      mobile: vendor.mobile,
      contactPerson: vendor.contact_person,
    };
  });

  lookup.byPan[vendor.pan] = registrations.map((registration) => ({
    ...registration,
    legalName: vendor.name,
    pan: vendor.pan,
    vendorType: vendor.vendor_type,
    email: vendor.email,
    mobile: vendor.mobile,
    contactPerson: vendor.contact_person,
  }));

  return lookup;
}, { byPan: {}, byGstin: {} });
